import subprocess

def generate_requirements_lock():
    """
    Generates a requirements.txt file with hashes for consistent dependency versions.
    """
    try:
        subprocess.run(['pip', 'freeze'], check=True, stdout=open('requirements.txt', 'w'))
        print("Requirements lock file generated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate requirements lock file: {e}")

